import { Link } from "react-router-dom";
import StatusDetails from "../../../utils/StatusDetails";
import StatusDrop from "../../../utils/StatusDrop";
import { v4 as uuidv4 } from 'uuid';
import { epochTogmt } from "../../../utils/Common";
import authService from "src/auth/auth.service";

export const tableJobDescriptionConstant = (fetchJobDescriptionList, handleConfirmModal, handleOpenNewPosition) => {
    return [
        {
            id: 1,
            name: "Position title",
            //grow: 2,
            width: '250px',
            cell: (row) => {
                return (
                    <Link to={`/career/job-description/edit/${row?.id}`}>
                        <span className="sub">{row.position}</span>
                    </Link>
                );
            },
            selector: (row) => row.position,
        },
        {
            id: 2,
            name: "Type",
            cell: (row) => {
                return (<span className="sub">{row.jobType === "FULL_TIME" ? "Full Time" : "Intern"}</span>
                );
            },
            sortable: true,
            reorder: true,
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
            //width: '300px',
            //grow: 5,
            //width: '300px'
        },
        {
            id: 4,
            name: "No.of open positions",
            //grow: 2.5,
            width: '150px',
            cell: (row) => {
                return (
                    row.status !== "DRAFT" ? 
                        <Link to={`/career/job-description-position/${row?.id}`}>
                            <span className="sub">{row.openPositionCount}</span>
                        </Link>
                     :
                        <span className="sub">{row.openPositionCount}</span>
                );
            },
        },
        {
            id: 3,
            //grow: 2.5,
            width: '160px',
            cell: (row) => {
                return (
                    <a href={"javascript:void(0)"} className={"link" + (row.status !== "ENABLE" ? " disable" : "")} onClick={(e) => { handleOpenNewPosition(row.id, row.position)}} style={{textDecoration: "none"}}>
                        <span className="sub">Open New Position</span>
                    </a>
                );
            },
        },
        {
            id: 5,
            name: "Action",
            //grow: 2.5,
            width: '150px',
            cell: (row) => {
                return (
                    <StatusDrop
                        id={row.id}
                        status={row.status}
                        type={'JOB_DESCRIPTION'}
                        action={fetchJobDescriptionList}
                        key={uuidv4()}
                        publishPermission={"JOB_DESCRIPTION_PUBLISH"}
                    />
                );
            },
            sortable: true,
            reorder: true,
        },
        {
            id: 6,
            name: "Status",
            cell: (row) => {
                return (
                    <StatusDetails status={row.status} key={uuidv4()} />
                );
            },
            //grow: 2.5,
            width: '150px',
            sortable: true,
            reorder: true,
        },
        {
            id: 7,
            name: "Department",
            //grow: 2.5,
            width: '150px',
            selector: (row) => row.department
        },
        {
            id: 8,
            name: "Date",
            //grow: 2.5,
            width: '150px',
            selector: (row) => epochTogmt(row.createTime)
        },
        {
            id: 8,
            name: "Delete",
            cell: (row) => {
                return <i className={"fa-regular fa-trash-can" + (row.status === "ENABLE" || !authService.getPermission("DELETE") ? " disable" : "")} onClick={(e) => { handleConfirmModal(row.id) }}></i>;
            },
            sortable: true,
            reorder: true,
        },
    ];
};
